const items = $input.all();
const raw = String(items[0].json.query || '').trim();

// Strip leading filler / command words (analyze, show me, tell me about, etc.)
let cleaned = raw
  .replace(/^(please\s+)?(can you\s+)?(analyze|analyse|show( me)?|tell me about|give me|get( me)?|fetch|find|lookup|look up|search( for)?|info( on)?|information( on| about)?|details( of| on| about)?|report( on)?|evaluate|review|about)\s+/i, '');

// Strip trailing plan/option qualifiers that make the premium search miss
// e.g. " - Direct Plan - Growth", "Regular Plan", "IDCW", "Growth Option"
cleaned = cleaned
  .replace(/\s*[-–—]\s*(direct|regular)\s*plan\b/gi, '')
  .replace(/\s*[-–—]\s*(growth|idcw|dividend|payout|reinvest(ment)?)\b.*$/gi, '')
  .replace(/\b(direct|regular)\s*plan\b/gi, '')
  .replace(/\b(growth|idcw|dividend)\s*(option|plan)?\b/gi, '')
  .replace(/\bplan\b/gi, '');

// Collapse leftover separators and whitespace
cleaned = cleaned
  .replace(/[-–—]+/g, ' ')
  .replace(/\s{2,}/g, ' ')
  .trim();

// Fallback: if normalization stripped everything, use the original
if (!cleaned) {
  cleaned = raw;
}

return [{
  json: {
    query: raw,
    original_query: raw,
    search_query: cleaned
  }
}];

const items = $input.all();
const premiumEnvelope = $('Fetch Scheme Detail (Premium)').first().json.body || $('Fetch Scheme Detail (Premium)').first().json || {};
const detailResponse = premiumEnvelope.data || premiumEnvelope || {};
const factsheetResponse = $('Fetch Factsheet (Premium)').first().json.data || $('Fetch Factsheet (Premium)').first().json.body?.data || $('Fetch Factsheet (Premium)').first().json.body || {};
const navResponse = $('Fetch NAV History (Premium)').first().json.body?.data || $('Fetch NAV History (Premium)').first().json.data || [];

const formatDate = (epochMs) => {
  const d = new Date(epochMs);
  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = d.getFullYear();
  return day + '-' + month + '-' + year;
};

const navHistory = Array.isArray(navResponse) ? navResponse.map(n => ({
  date: formatDate(n[0]),
  nav: parseFloat(n[1]) || 0
})) : [];

const mfData = detailResponse.mf_data || {};
const schemeList = Array.isArray(mfData.scheme) ? mfData.scheme : [];
const scheme0 = schemeList[0] || {};
const riskList = Array.isArray(mfData.risk_volatility) ? mfData.risk_volatility : [];
const risk3 = riskList.find((entry) => Number(entry?.period_years) === 3 || String(entry?.period_years) === '3') || riskList[0] || {};

const holdings = (mfData.equity_holdings || detailResponse.holdings || []).map(h => ({
  security: h.holding_name || h.security_name || h.Holding_Name || h.name || "",
  weight: parseFloat(h.portfolio_weight || h.weight_percent || h.Portfolio_Weight || h.weight) || 0
}));

const aum = parseFloat(scheme0.total_assets ?? scheme0.aum ?? detailResponse.aum ?? detailResponse.total_aum ?? detailResponse.Asset_Size);
const expenseRatio = parseFloat(scheme0.expense_ratio ?? detailResponse.expense_ratio ?? detailResponse.ter);
const riskShapre = parseFloat(risk3.sharpe_ratio ?? risk3.sharpe ?? detailResponse.risk_metrics?.sharpe_ratio ?? detailResponse.sharpe_ratio);
const riskBeta = parseFloat(risk3.beta ?? detailResponse.risk_metrics?.beta ?? detailResponse.beta);
const riskAlpha = parseFloat(risk3.alpha ?? detailResponse.risk_metrics?.alpha ?? detailResponse.alpha);
const riskStdDev = parseFloat(risk3.standard_deviation ?? risk3.std_dev ?? risk3.standard_deviation_pct ?? detailResponse.risk_metrics?.standard_deviation ?? detailResponse.standard_deviation);

const supplemental = Array.isArray(mfData.supplemental_data) ? (mfData.supplemental_data[0] || {}) : {};
const rawCategory = supplemental.sebi_category_name || supplemental.sub_asset_class || scheme0.category || detailResponse.scheme_sub_category || detailResponse.scheme_category || '';
const category = String(rawCategory).replace(/-/g, ' ').replace(/\s+/g, ' ').trim();

const output = {
  scheme_code: String(detailResponse.scheme_code || detailResponse.scheme_amfi_code || detailResponse.amfi_code || detailResponse.BSE_Code || scheme0.scheme_code || ""),
  isin: String(detailResponse.scheme_isin || detailResponse.isin || detailResponse.schemeISIN || scheme0.isin || factsheetResponse.isin || ""),
  amc_name: detailResponse.scheme_amc_name || detailResponse.fund_house || detailResponse.amc_name || detailResponse.asset_manager || scheme0.fund_house || factsheetResponse.fund_name || "",
  name: detailResponse.name || detailResponse.scheme_name || scheme0.scheme_name || "",
  category: category,
  nav_history: navHistory,
  enriched: true,
  holdings: holdings,
  aum: Number.isFinite(aum) ? aum : null,
  expense_ratio: Number.isFinite(expenseRatio) ? expenseRatio : null,
  risk_metrics: {
    sharpe: Number.isFinite(riskShapre) ? riskShapre : null,
    beta: Number.isFinite(riskBeta) ? riskBeta : null,
    alpha: Number.isFinite(riskAlpha) ? riskAlpha : null,
    std_dev: Number.isFinite(riskStdDev) ? riskStdDev : null
  },
  factsheet_url: factsheetResponse.factsheet_url || factsheetResponse.link || factsheetResponse.pdf_link || detailResponse.factsheet_url || null
};

return [{ json: output }];

const items = $input.all();
const publicDetails = $('Fetch Public Details (NAV History)').first().json.body || $('Fetch Public Details (NAV History)').first().json || {};

const meta = publicDetails.meta || {};
const rawData = publicDetails.data || [];

const navHistory = rawData.map(n => ({
  date: n.date,
  nav: parseFloat(n.nav) || 0
}));

const output = {
  scheme_code: String(meta.scheme_code || ""),
  isin: String(meta.scheme_isin || meta.isin || ""),
  amc_name: meta.fund_house || meta.amc_name || "",
  name: meta.scheme_name || "",
  nav_history: navHistory,
  enriched: false,
  holdings: [],
  aum: null,
  expense_ratio: null,
  risk_metrics: {
    sharpe: null,
    beta: null,
    alpha: null,
    std_dev: null
  },
  factsheet_url: null
};

return [{ json: output }];
